<section id="partnership" class="w-full bg-white py-16 lg:py-24">
    <div class="max-w-[1440px] mx-auto px-6 md:px-20 lg:px-[120px]">

        {{-- Header --}}
        <div class="text-center mb-14">
            <div class="inline-block px-5 py-1.5 mb-4 bg-gray-200 rounded-full">
                <span class="text-[#432108] text-sm font-medium font-['Poppins']">Partner Kami</span>
            </div>
            <h2 class="text-black text-3xl lg:text-4xl font-bold font-['Poppins'] mb-3">
                Coffee Shop dan Supplier kami
            </h2>
            <p class="text-[#926849] text-base font-medium font-['Poppins'] max-w-2xl mx-auto leading-relaxed">
                Terimakasih kepada partner yang telah mempercayakan ampas kopi
                mereka kepada kami untuk diolah menjadi produk bernilai.
            </p>
        </div>

        {{-- Logo Partner Slider --}}
        <div class="mb-10">
            <div class="flex gap-5 overflow-x-auto scroll-smooth snap-x snap-mandatory pb-3
                        [scrollbar-width:none] [-ms-overflow-style:none] [&::-webkit-scrollbar]:hidden">

                {{-- Tomoro Coffee --}}
                <div class="snap-start flex-shrink-0 w-[188px] h-[188px] bg-white rounded-[20px]
                            shadow-[0_10px_30px_-5px_rgba(0,0,0,0.12)]
                            flex flex-col items-center justify-center gap-3 p-5">
                    <svg xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink" width="112" height="112" viewBox="0 0 112 112" fill="none">
                        <rect width="112" height="112" rx="20" fill="url(#pattern0_81_399)"/>
                        <defs>
                        <pattern id="pattern0_81_399" patternContentUnits="objectBoundingBox" width="1" height="1">
                        <use xlink:href="#image0_81_399" transform="scale(0.00166667)"/>
                        </pattern>
                        <image id="image0_81_399" width="600" height="600" preserveAspectRatio="none" xlink:href="data:image/png;base64,"/>
                        </defs>
                    </svg>
                    <p class="text-black text-[15px] font-semibold font-['Poppins'] text-center leading-tight">Tomoro Coffee</p>
                </div>

                {{-- Kopi Soe --}}
                <div class="snap-start flex-shrink-0 w-[188px] h-[188px] bg-white rounded-[20px]
                            shadow-[0_10px_30px_-5px_rgba(0,0,0,0.12)]
                            flex flex-col items-center justify-center gap-3 p-5">
                    <svg xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink" width="154" height="109" viewBox="0 0 154 109" fill="none">
                        <rect width="154" height="109" fill="url(#pattern0_81_140)"/>
                        <defs>
                        <pattern id="pattern0_81_140" patternContentUnits="objectBoundingBox" width="1" height="1">
                        <use xlink:href="#image0_81_140" transform="matrix(0.000285285 0 0 0.000403063 -0.000389977 0)"/>
                        </pattern>
                        <image id="image0_81_140" width="3508" height="2481" preserveAspectRatio="none" xlink:href="data:image/png;base64,"/>
                        </defs>
                    </svg>
                    <p class="text-black text-[15px] font-semibold font-['Poppins'] text-center leading-tight">Kopi Soe</p>
                </div>

                {{-- Point Coffee --}}
                <div class="snap-start flex-shrink-0 w-[188px] h-[188px] bg-white rounded-[20px]
                            shadow-[0_10px_30px_-5px_rgba(0,0,0,0.12)]
                            flex flex-col items-center justify-center gap-3 p-5">
                    <svg xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink" width="111" height="111" viewBox="0 0 111 111" fill="none">
                        <rect width="111" height="111" rx="12" fill="url(#pattern0_81_208)"/>
                        <defs>
                        <pattern id="pattern0_81_208" patternContentUnits="objectBoundingBox" width="1" height="1">
                        <use xlink:href="#image0_81_208" transform="scale(0.000925926)"/>
                        </pattern>
                        <image id="image0_81_208" width="1080" height="1080" preserveAspectRatio="none" xlink:href="data:image/png;base64,"/>
                        </defs>
                    </svg>
                    <p class="text-black text-[15px] font-semibold font-['Poppins'] text-center leading-tight">Point Coffee</p>
                </div>

                {{-- Fore Coffee --}}
                <div class="snap-start flex-shrink-0 w-[188px] h-[188px] bg-white rounded-[20px]
                            shadow-[0_10px_30px_-5px_rgba(0,0,0,0.12)]
                            flex flex-col items-center justify-center gap-3 p-5">
                    <svg xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink" width="114" height="114" viewBox="0 0 114 114" fill="none">
                        <rect width="114" height="114" rx="21" fill="url(#pattern0_81_145)"/>
                        <defs>
                        <pattern id="pattern0_81_145" patternContentUnits="objectBoundingBox" width="1" height="1">
                        <use xlink:href="#image0_81_145" transform="scale(0.000925926)"/>
                        </pattern>
                        <image id="image0_81_145" width="1080" height="1080" preserveAspectRatio="none" xlink:href="data:image/png;base64,"/>
                        </defs>
                    </svg>
                    <p class="text-black text-[15px] font-semibold font-['Poppins'] text-center leading-tight">Fore Coffee</p>
                </div>

                {{-- Janji Jiwa --}}
                <div class="snap-start flex-shrink-0 w-[188px] h-[188px] bg-white rounded-[20px]
                            shadow-[0_10px_30px_-5px_rgba(0,0,0,0.12)]
                            flex flex-col items-center justify-center gap-3 p-5">
                    <svg xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink" width="104" height="103" viewBox="0 0 104 103" fill="none">
                        <rect width="104" height="103" rx="10" fill="url(#pattern0_81_189)"/>
                        <defs>
                        <pattern id="pattern0_81_189" patternContentUnits="objectBoundingBox" width="1" height="1">
                        <use xlink:href="#image0_81_189" transform="matrix(0.005 0 0 0.00504854 0 -0.00485437)"/>
                        </pattern>
                        <image id="image0_81_189" width="200" height="200" preserveAspectRatio="none" xlink:href="data:image/png;base64,"/>
                        </defs>
                    </svg>
                    <p class="text-black text-[15px] font-semibold font-['Poppins'] text-center leading-tight">Janji Jiwa</p>
                </div>

                {{-- Kopi Tuku --}}
                <div class="snap-start flex-shrink-0 w-[188px] h-[188px] bg-white rounded-[20px]
                            shadow-[0_10px_30px_-5px_rgba(0,0,0,0.12)]
                            flex flex-col items-center justify-center gap-3 p-5">
                    <svg xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink" width="138" height="97" viewBox="0 0 138 97" fill="none">
                        <rect width="138" height="97" fill="url(#pattern0_81_196)"/>
                        <defs>
                        <pattern id="pattern0_81_196" patternContentUnits="objectBoundingBox" width="1" height="1">
                        <use xlink:href="#image0_81_196" transform="matrix(0.00299401 0 0 0.00422232 0 -0.192308)"/>
                        </pattern>
                        <image id="image0_81_196" width="334" height="334" preserveAspectRatio="none" xlink:href="data:image/png;base64,"/>
                        </defs>
                    </svg>
                    <p class="text-black text-[15px] font-semibold font-['Poppins'] text-center leading-tight">Kopi Tuku</p>
                </div>

                {{-- Kopi Kenangan --}}
                <div class="snap-start flex-shrink-0 w-[188px] h-[188px] bg-white rounded-[20px]
                            shadow-[0_10px_30px_-5px_rgba(0,0,0,0.12)]
                            flex flex-col items-center justify-center gap-3 p-5">
                    <img src="{{ asset('assets/kopi-kenangan.png') }}" alt="Kopi Kenangan"
                        class="w-[114px] h-[114px] object-contain">
                    <p class="text-black text-[15px] font-semibold font-['Poppins'] text-center leading-tight">Kopi Kenangan</p>
                </div>

            </div>
        </div>

        {{-- CTA Cards --}}
        <div class="grid grid-cols-1 md:grid-cols-2 gap-6 max-w-[1200px] mx-auto">

            {{-- Coffeeshop (filled green) --}}
            <div class="bg-[#4c6444] rounded-[33px] px-12 py-8 flex flex-col items-center justify-center text-center min-h-[195px]">
                <h3 class="text-white text-2xl font-bold font-['Poppins'] mb-3">Coffeeshop</h3>
                <p class="text-white text-lg font-medium font-['Poppins'] leading-relaxed max-w-md">
                    Tidak perlu pusing membuang ampas kopi. Akan kami jemput dan
                    anda akan berkontribusi pada lingkungan
                </p>
            </div>

            {{-- Supplier (outlined green) --}}
            <div class="bg-white border-2 border-[#4c6444] rounded-[33px] px-12 py-8 flex flex-col items-center justify-center text-center min-h-[195px]">
                <h3 class="text-[#4c6444] text-2xl font-bold font-['Poppins'] mb-3">Supplier</h3>
                <p class="text-[#4c6444] text-lg font-medium font-['Poppins'] leading-relaxed max-w-md">
                    Punya ampas kopi dalam jumlah besar? Mari berkontribusi pada
                    lingkungan untuk keberlanjutan bersama!
                </p>
            </div>

        </div>

    </div>
</section>